  "phases": [
    {
      "id": "01",
      "name": "Settings API and UI",
      "steps": [
        {
          "id": "01-01",
          "name": "Backend: include sandbox_provider in settings GET/PUT",
          "criteria": "GIVEN a workspace with settings.sandbox_provider set WHEN GET /settings is called THEN sandboxProvider is returned. GIVEN no sandbox_provider configured WHEN GET /settings is called THEN sandboxProvider is omitted. GIVEN a valid sandboxProvider WHEN PUT /settings is called THEN it persists. GIVEN an invalid sandboxProvider WHEN PUT /settings is called THEN 400 is returned. GIVEN only sandboxProvider in PUT body WHEN PUT /settings is called THEN it succeeds.",
          "files_to_modify": [
            "app/src/server/workspace/workspace-routes.ts"
          ],
          "time_estimate_minutes": 30,
          "dependencies": []
        },
        {
          "id": "01-02",
          "name": "Frontend: add sandbox provider select to settings page",
          "criteria": "GIVEN the settings page WHEN it renders THEN a Sandbox Provider section with Select dropdown is shown. GIVEN a configured provider WHEN the page loads THEN the current provider is displayed. GIVEN no provider configured WHEN the page loads THEN 'Not configured' placeholder is shown. GIVEN the user selects a provider WHEN the selection changes THEN PUT /settings is called with sandboxProvider.",
          "files_to_modify": [
            "app/src/client/routes/settings-page.tsx"
          ],
          "time_estimate_minutes": 30,
          "dependencies": ["01-01"]
        }
      ]
    }
  ],
  "validation": { "status": "approved" }
}
